var _cemCurrentSpan=null;var _cemComments=[];var _cemCommentIdSeq=0;var _cemSavedSel=null;var _cemSavedRangeForFontSize=null;var CEM_TEXT_COLORS=["#000000","#ffffff","#e53935","#d81b60","#8e24aa","#1e88e5","#00897b","#43a047","#f4511e","#fb8c00","#fdd835","#6d4c41","#546e7a","#1565c0","#2e7d32"];var CEM_HIGHLIGHT_COLORS=["transparent","rgba(255,235,59,0.6)","rgba(76,175,80,0.45)","rgba(33,150,243,0.4)","rgba(244,67,54,0.4)","rgba(156,39,176,0.4)","rgba(255,152,0,0.5)"];function initChipEditor(){_cemBuildModal();_cemBindAll()}function openChipEditor(span){var overlay=document.getElementById("chip-editor-overlay");var editArea=document.getElementById("cem-edit-area");var titleEl=document.getElementById("cem-title");var commentInputWrap=document.getElementById("cem-comment-input-wrap");if(!overlay||!editArea)return;_cemCurrentSpan=span;var isMsg=span.classList.contains("message-cite");var refEl=span.querySelector(".cite-ref");var ref=refEl?refEl.textContent.trim():isMsg?"✍️ Послание":"📖 Стих";if(titleEl)titleEl.textContent="Редактировать: "+ref;var verseEl=span.querySelector(".cite-verse-text");var htmlAttr=isMsg?"data-para-html":"data-verse-html";var savedHtml=span.getAttribute(htmlAttr)||"";if(!savedHtml&&verseEl)savedHtml=verseEl.innerHTML;if(!savedHtml)savedHtml=span.getAttribute("data-verse-text")||span.getAttribute("data-para-text")||"";editArea.innerHTML=savedHtml;var commJson=span.getAttribute("data-verse-comments")||"[]";try{_cemComments=JSON.parse(commJson)}catch(e){_cemComments=[]}_cemCommentIdSeq=_cemComments.reduce(function(mx,c){var n=parseInt((c.id||"").replace("c",""))||0;return n>mx?n:mx},0);_cemRenderComments();if(commentInputWrap)commentInputWrap.classList.remove("open");overlay.classList.add("open");setTimeout(function(){editArea.focus()},60)}function _cemBuildModal(){if(document.getElementById("chip-editor-overlay"))return;var div=document.createElement("div");div.innerHTML=_cemModalTemplate();document.body.appendChild(div.firstElementChild);var style=document.createElement("style");style.textContent=_cemModalCSS();document.head.appendChild(style)}function _cemModalTemplate(){return'<div id="chip-editor-overlay">'+'<div id="chip-editor-modal">'+'<div class="cem-header">'+'<span class="cem-title" id="cem-title">Редактировать</span>'+'<button class="cem-close" id="cem-close-btn" type="button">×</button>'+"</div>"+'<div class="cem-toolbar">'+'<button class="cem-btn" id="cem-bold"      type="button"><b>Ж</b></button>'+'<button class="cem-btn" id="cem-italic"    type="button"><i>К</i></button>'+'<button class="cem-btn" id="cem-underline" type="button"><u>П</u></button>'+'<div class="cem-sep"></div>'+'<div class="cem-color-wrap" id="cem-tc-wrap">'+'<div class="cem-swatch-btn" id="cem-tc-btn" title="Цвет текста">'+'<span style="font-size:13px;font-weight:700;color:inherit;">A</span>'+'<div class="cem-swatch-bar" id="cem-tc-bar" style="background:#e53935;"></div>'+"</div>"+'<div class="cem-color-dd" id="cem-tc-dd"></div>'+"</div>"+'<div class="cem-color-wrap" id="cem-hl-wrap">'+'<div class="cem-swatch-btn" id="cem-hl-btn" title="Выделение фона">'+'<span style="font-size:12px;">🖊</span>'+'<div class="cem-swatch-bar" id="cem-hl-bar" style="background:rgba(255,235,59,0.6);"></div>'+"</div>"+'<div class="cem-color-dd" id="cem-hl-dd"></div>'+"</div>"+'<div class="cem-sep"></div>'+'<span class="cem-label">Размер:</span>'+'<input class="cem-fontsize" id="cem-fontsize" type="number" min="8" max="72" value="15" />'+'<button class="cem-btn" id="cem-apply-size" type="button">✓</button>'+'<div class="cem-sep"></div>'+'<button class="cem-btn" id="cem-clear-fmt" type="button">✕ сброс</button>'+"</div>"+'<div id="cem-comment-input-wrap">'+'<span class="cem-ci-label">Комментарий:</span>'+'<input id="cem-ci-text" type="text" placeholder="Введите комментарий к выделению…" maxlength="300" />'+'<button class="cem-ci-ok"  id="cem-ci-ok"     type="button">Добавить</button>'+'<button class="cem-ci-can" id="cem-ci-cancel"  type="button">Отмена</button>'+"</div>"+'<div id="cem-edit-area" contenteditable="true" spellcheck="false"></div>'+'<div class="cem-comments">'+'<div class="cem-comments-hdr">'+"<span>💬 Комментарии к фразам</span>"+'<button class="cem-add-c-btn" id="cem-add-c-btn" type="button">+ К выделению</button>'+"</div>"+'<div id="cem-comments-list">'+'<div class="cem-no-c" id="cem-no-c">Нет комментариев</div>'+"</div>"+"</div>"+'<div class="cem-footer">'+'<button class="cem-cancel-btn" id="cem-cancel-btn" type="button">Отмена</button>'+'<button class="cem-save-btn"   id="cem-save-btn"   type="button">💾 Сохранить</button>'+"</div>"+"</div>"+"</div>"}function _cemBindAll(){var overlay=document.getElementById("chip-editor-overlay");var editArea=document.getElementById("cem-edit-area");if(!overlay||!editArea)return;overlay.addEventListener("mousedown",function(e){if(e.target===overlay)_cemClose(false)});document.getElementById("cem-close-btn").addEventListener("click",function(){_cemClose(false)});document.getElementById("cem-cancel-btn").addEventListener("click",function(){_cemClose(false)});document.getElementById("cem-save-btn").addEventListener("click",function(){_cemClose(true)});document.addEventListener("keydown",function(e){if(e.keyCode===27&&overlay.classList.contains("open"))_cemClose(false)});editArea.addEventListener("keydown",function(e){var ctrl=e.ctrlKey||e.metaKey;if(ctrl&&[66,73,85,90,89,65,67].indexOf(e.keyCode)>=0)return;if(e.keyCode>=33&&e.keyCode<=40)return;if([16,17,18,91,92,93].indexOf(e.keyCode)>=0)return;if(e.keyCode===27)return;if(e.keyCode>=112&&e.keyCode<=123)return;e.preventDefault()});editArea.addEventListener("paste",function(e){e.preventDefault()});editArea.addEventListener("drop",function(e){e.preventDefault()});editArea.addEventListener("keyup",_cemUpdateToolbar);editArea.addEventListener("mouseup",_cemUpdateToolbar);["cem-bold","cem-italic","cem-underline"].forEach(function(id){var btn=document.getElementById(id);if(!btn)return;btn.addEventListener("mousedown",function(e){e.preventDefault();var cmd=id==="cem-bold"?"bold":id==="cem-italic"?"italic":"underline";document.execCommand(cmd,false,null);_cemUpdateToolbar()})});document.getElementById("cem-clear-fmt").addEventListener("mousedown",function(e){e.preventDefault();document.execCommand("removeFormat",false,null);_cemUpdateToolbar()});document.getElementById("cem-tc-btn").addEventListener("mousedown",function(e){e.preventDefault();_cemToggleDd("tc")});_cemBuildColorDd("cem-tc-dd",CEM_TEXT_COLORS,function(c){document.execCommand("foreColor",false,c);document.getElementById("cem-tc-bar").style.background=c});document.getElementById("cem-hl-btn").addEventListener("mousedown",function(e){e.preventDefault();_cemToggleDd("hl")});_cemBuildColorDd("cem-hl-dd",CEM_HIGHLIGHT_COLORS,function(c){_cemApplyHighlight(c);document.getElementById("cem-hl-bar").style.background=c==="transparent"?"linear-gradient(135deg,#fff 45%,#e53935 45%)":c});document.addEventListener("mousedown",function(e){if(!e.target.closest("#cem-tc-wrap"))_cemHideDd("tc");if(!e.target.closest("#cem-hl-wrap"))_cemHideDd("hl")});document.getElementById("cem-fontsize").addEventListener("mousedown",function(){var sel=window.getSelection();if(sel&&sel.rangeCount>0&&editArea.contains(sel.anchorNode)){_cemSavedRangeForFontSize=sel.getRangeAt(0).cloneRange()}});document.getElementById("cem-apply-size").addEventListener("mousedown",function(e){e.preventDefault();_cemApplyFontSize()});document.getElementById("cem-fontsize").addEventListener("keydown",function(e){if(e.keyCode===13){e.preventDefault();_cemApplyFontSize()}});document.getElementById("cem-add-c-btn").addEventListener("mousedown",function(e){e.preventDefault();var sel=window.getSelection();if(!sel||sel.isCollapsed||!editArea.contains(sel.anchorNode)){alert("Сначала выделите фразу в тексте стиха.");return}_cemSavedSel={range:sel.getRangeAt(0).cloneRange(),text:sel.toString().trim()};document.getElementById("cem-ci-text").value="";document.getElementById("cem-comment-input-wrap").classList.add("open");setTimeout(function(){document.getElementById("cem-ci-text").focus()},30)});document.getElementById("cem-ci-ok").addEventListener("click",_cemConfirmComment);document.getElementById("cem-ci-cancel").addEventListener("click",function(){document.getElementById("cem-comment-input-wrap").classList.remove("open");_cemSavedSel=null});document.getElementById("cem-ci-text").addEventListener("keydown",function(e){if(e.keyCode===13)_cemConfirmComment();if(e.keyCode===27){document.getElementById("cem-comment-input-wrap").classList.remove("open");_cemSavedSel=null}})}function _cemToggleDd(which){var ddId=which==="tc"?"cem-tc-dd":"cem-hl-dd";var othId=which==="tc"?"cem-hl-dd":"cem-tc-dd";var dd=document.getElementById(ddId);var oth=document.getElementById(othId);if(oth)oth.style.display="none";if(dd)dd.style.display=dd.style.display==="flex"?"none":"flex"}function _cemHideDd(which){var dd=document.getElementById(which==="tc"?"cem-tc-dd":"cem-hl-dd");if(dd)dd.style.display="none"}function _cemBuildColorDd(ddId,colors,applyFn){var dd=document.getElementById(ddId);if(!dd)return;colors.forEach(function(c){var dot=document.createElement("div");dot.className="cem-color-dot";dot.style.background=c==="transparent"?"linear-gradient(135deg,#fff 45%,#e53935 45%)":c;dot.title=c;dot.addEventListener("mousedown",function(e){e.preventDefault();applyFn(c);_cemHideDd(ddId.includes("tc")?"tc":"hl");_cemUpdateToolbar()});dd.appendChild(dot)})}function _cemApplyHighlight(color){var editArea=document.getElementById("cem-edit-area");var sel=window.getSelection();if(!sel||sel.isCollapsed||!editArea.contains(sel.anchorNode))return;if(color==="transparent"){document.execCommand("removeFormat",false,null);return}var range=sel.getRangeAt(0);var span=document.createElement("span");span.style.backgroundColor=color;span.style.borderRadius="2px";try{range.surroundContents(span)}catch(ex){document.execCommand("backColor",false,color)}}function _cemApplyFontSize(){var editArea=document.getElementById("cem-edit-area");var input=document.getElementById("cem-fontsize");var sz=parseInt(input.value);if(isNaN(sz)||sz<8)sz=8;if(sz>72)sz=72;input.value=sz;if(_cemSavedRangeForFontSize){var sel=window.getSelection();sel.removeAllRanges();sel.addRange(_cemSavedRangeForFontSize);_cemSavedRangeForFontSize=null}editArea.focus();var sel2=window.getSelection();if(!sel2||sel2.isCollapsed)return;document.execCommand("fontSize",false,"7");editArea.querySelectorAll('font[size="7"]').forEach(function(f){var sp=document.createElement("span");sp.style.fontSize=sz+"px";while(f.firstChild)sp.appendChild(f.firstChild);f.parentNode.replaceChild(sp,f)});_cemUpdateToolbar()}function _cemUpdateToolbar(){var b=document.getElementById("cem-bold");var i=document.getElementById("cem-italic");var u=document.getElementById("cem-underline");if(b)b.classList.toggle("cem-active",document.queryCommandState("bold"));if(i)i.classList.toggle("cem-active",document.queryCommandState("italic"));if(u)u.classList.toggle("cem-active",document.queryCommandState("underline"))}function _cemConfirmComment(){var editArea=document.getElementById("cem-edit-area");var ciWrap=document.getElementById("cem-comment-input-wrap");var ciText=document.getElementById("cem-ci-text");var text=ciText.value.trim();if(!text||!_cemSavedSel)return;_cemCommentIdSeq++;var cid="c"+_cemCommentIdSeq;var cnum=_cemComments.length+1;var hlTxt=_cemSavedSel.text.substring(0,60);var hlBg=CEM_HIGHLIGHT_COLORS[1];var sel=window.getSelection();sel.removeAllRanges();sel.addRange(_cemSavedSel.range);var cs=document.createElement("span");cs.className="verse-comment";cs.setAttribute("data-cid",cid);cs.setAttribute("data-cnum",cnum);cs.style.backgroundColor=hlBg;cs.style.borderRadius="3px";cs.style.padding="0 2px";try{_cemSavedSel.range.surroundContents(cs)}catch(ex){document.execCommand("backColor",false,hlBg)}_cemComments.push({id:cid,cnum:cnum,highlightText:hlTxt,text:text});_cemRenderComments();ciWrap.classList.remove("open");_cemSavedSel=null;ciText.value="";editArea.focus()}function _cemRenderComments(){var list=document.getElementById("cem-comments-list");var noMsg=document.getElementById("cem-no-c");if(!list)return;list.querySelectorAll(".cem-c-item").forEach(function(el){el.remove()});if(_cemComments.length===0){if(noMsg)noMsg.style.display="";return}if(noMsg)noMsg.style.display="none";_cemComments.forEach(function(c){var item=document.createElement("div");item.className="cem-c-item";item.innerHTML='<div class="cem-c-num">'+c.cnum+"</div>"+'<div class="cem-c-body">'+'<div class="cem-c-hl">«'+_cemEsc(c.highlightText)+"»</div>"+'<div class="cem-c-txt">'+_cemEsc(c.text)+"</div>"+"</div>"+'<button class="cem-c-del" data-cid="'+c.id+'" type="button">×</button>';item.querySelector(".cem-c-del").addEventListener("click",function(){_cemDeleteComment(c.id)});list.appendChild(item)})}function _cemDeleteComment(cid){var editArea=document.getElementById("cem-edit-area");var el=editArea.querySelector('[data-cid="'+cid+'"]');if(el){var p=el.parentNode;while(el.firstChild)p.insertBefore(el.firstChild,el);p.removeChild(el)}_cemComments=_cemComments.filter(function(c){return c.id!==cid});_cemComments.forEach(function(c,i){c.cnum=i+1});editArea.querySelectorAll(".verse-comment").forEach(function(el){var c=_cemComments.find(function(x){return x.id===el.getAttribute("data-cid")});if(c)el.setAttribute("data-cnum",c.cnum)});_cemRenderComments()}function _cemToInlineHtml(html){var tmp=document.createElement("div");tmp.innerHTML=html;tmp.querySelectorAll("div, p").forEach(function(el){var space=document.createTextNode(" ");el.parentNode.insertBefore(space,el);while(el.firstChild)el.parentNode.insertBefore(el.firstChild,el);el.parentNode.removeChild(el)});tmp.querySelectorAll("br").forEach(function(el){el.parentNode.replaceChild(document.createTextNode(" "),el)});return tmp.innerHTML.replace(/\s{2,}/g," ").trim()}function _cemClose(save){var overlay=document.getElementById("chip-editor-overlay");var editArea=document.getElementById("cem-edit-area");if(!overlay)return;if(save&&_cemCurrentSpan){var html=editArea.innerHTML;var commentsJson=JSON.stringify(_cemComments);var isMsg=_cemCurrentSpan.classList.contains("message-cite");_cemCurrentSpan.setAttribute(isMsg?"data-para-html":"data-verse-html",html);_cemCurrentSpan.setAttribute("data-verse-comments",commentsJson);var verseEl=_cemCurrentSpan.querySelector(".cite-verse-text");if(verseEl){verseEl.innerHTML=html}else if(isMsg){var removeBtn=_cemCurrentSpan.querySelector(".cite-remove");var hint=_cemCurrentSpan.querySelector(".cite-edit-hint");_cemCurrentSpan.innerHTML="✍️ "+_cemToInlineHtml(html);if(hint){var newHint=document.createElement("span");newHint.className="cite-edit-hint";newHint.textContent="двойной клик — редактировать";_cemCurrentSpan.appendChild(newHint)}if(removeBtn)_cemCurrentSpan.appendChild(removeBtn)}if(window._sermonScheduleAutoSave)window._sermonScheduleAutoSave();else if(typeof scheduleAutoSave==="function")scheduleAutoSave()}overlay.classList.remove("open");_cemCurrentSpan=null;_cemComments=[]}function _cemEsc(s){return String(s||"").replace(/&/g,"&amp;").replace(/</g,"&lt;").replace(/>/g,"&gt;").replace(/"/g,"&quot;")}function _cemModalCSS(){return`\n/* ── Overlay ───────────────────────────────────────────── */\n#chip-editor-overlay {\n    display: none; position: fixed; inset: 0;\n    background: rgba(0,0,0,.65); z-index: 4000;\n    align-items: center; justify-content: center;\n}\n#chip-editor-overlay.open { display: flex; }\n\n/* ── Modal box ─────────────────────────────────────────── */\n#chip-editor-modal {\n    background: #fff; border-radius: 14px;\n    box-shadow: 0 8px 40px rgba(0,0,0,.28);\n    width: min(720px, 96vw); max-height: 92vh;\n    display: flex; flex-direction: column; overflow: hidden;\n}\n\n/* ── Header ────────────────────────────────────────────── */\n.cem-header {\n    background: #f8f9fa; border-bottom: 1.5px solid #dee2e6;\n    padding: 11px 18px; display: flex;\n    align-items: center; justify-content: space-between; flex-shrink: 0;\n}\n.cem-title { font-size: 14px; font-weight: 700; color: #2c3e50; }\n.cem-close {\n    width: 28px; height: 28px; border: none; background: none;\n    font-size: 20px; cursor: pointer; color: #888; border-radius: 6px;\n    display: flex; align-items: center; justify-content: center; line-height:1;\n    transition: background .12s;\n}\n.cem-close:hover { background: #f0f0f0; color: #333; }\n\n/* ── Toolbar ───────────────────────────────────────────── */\n.cem-toolbar {\n    display: flex; flex-wrap: wrap; gap: 4px;\n    padding: 8px 12px; background: #f8f9fa;\n    border-bottom: 1.5px solid #dee2e6;\n    flex-shrink: 0; align-items: center;\n}\n.cem-btn {\n    padding: 4px 10px; border: 1.5px solid #dee2e6;\n    background: #fff; border-radius: 6px; cursor: pointer;\n    font-size: 13px; height: 30px;\n    display: flex; align-items: center; gap: 3px;\n    color: #2c3e50; transition: all .12s;\n    /* ВАЖНО: нет outline при фокусе, т.к. кнопки используют mousedown */\n    outline: none;\n}\n.cem-btn:hover { background: #f0f4f8; border-color: #c8d0db; }\n.cem-btn.cem-active { background: #1a6db5; color: #fff; border-color: #1a6db5; }\n\n.cem-sep { width: 1px; height: 22px; background: #dee2e6; margin: 0 2px; flex-shrink: 0; }\n.cem-label { font-size: 12px; color: #888; flex-shrink: 0; }\n\n.cem-fontsize {\n    width: 46px; border: 1.5px solid #dee2e6;\n    border-radius: 6px; padding: 2px 6px;\n    font-size: 13px; text-align: center; height: 30px; outline: none;\n}\n.cem-fontsize:focus { border-color: #1a6db5; }\n\n/* ── Colour swatch button ──────────────────────────────── */\n.cem-color-wrap { position: relative; display: inline-flex; align-items: center; }\n.cem-swatch-btn {\n    display: flex; flex-direction: column; align-items: center;\n    width: 28px; padding: 3px 2px;\n    border: 1.5px solid #dee2e6; border-radius: 6px;\n    cursor: pointer; background: #fff;\n    gap: 2px; transition: border-color .12s;\n    outline: none; /* убираем outline */\n}\n.cem-swatch-btn:hover { border-color: #1a6db5; background: #f0f4f8; }\n.cem-swatch-bar { width: 20px; height: 4px; border-radius: 2px; flex-shrink: 0; }\n\n.cem-color-dd {\n    display: none; position: absolute; top: 36px; left: 0;\n    background: #fff; border: 1.5px solid #dee2e6;\n    border-radius: 8px; padding: 8px; gap: 5px;\n    flex-wrap: wrap; width: 152px; z-index: 5000;\n    box-shadow: 0 4px 16px rgba(0,0,0,.14);\n}\n.cem-color-dot {\n    width: 22px; height: 22px; border-radius: 4px;\n    cursor: pointer; border: 2px solid transparent;\n    transition: border-color .1s, transform .1s;\n}\n.cem-color-dot:hover { border-color: #333; transform: scale(1.12); }\n\n/* ── Comment input row ─────────────────────────────────── */\n#cem-comment-input-wrap {\n    display: none; padding: 9px 14px;\n    background: #fff8e6; border-bottom: 1.5px solid #f0c040;\n    align-items: center; gap: 8px; flex-wrap: wrap; flex-shrink: 0;\n}\n#cem-comment-input-wrap.open { display: flex; }\n.cem-ci-label { font-size: 12px; font-weight: 600; color: #7a5a00; flex-shrink: 0; }\n#cem-ci-text {\n    flex: 1; min-width: 160px;\n    border: 1.5px solid #f0c040; border-radius: 6px;\n    padding: 5px 10px; font-size: 13px; outline: none; background: #fff;\n}\n#cem-ci-text:focus { border-color: #e6a800; }\n.cem-ci-ok {\n    padding: 5px 14px; border: none; background: #e6a800;\n    color: #fff; border-radius: 6px; cursor: pointer;\n    font-size: 13px; font-weight: 600; transition: background .12s;\n}\n.cem-ci-ok:hover { background: #c8900a; }\n.cem-ci-can {\n    padding: 5px 12px; border: 1.5px solid #ddd;\n    background: #fff; border-radius: 6px; cursor: pointer;\n    font-size: 13px; transition: background .12s;\n}\n.cem-ci-can:hover { background: #f0f0f0; }\n\n/* ── Edit area ─────────────────────────────────────────── */\n#cem-edit-area {\n    min-height: 80px; max-height: 200px; overflow-y: auto;\n    padding: 14px 18px; font-size: 15px; line-height: 1.7;\n    outline: none; white-space: pre-wrap; word-break: break-word;\n    color: #1a2533; border-bottom: 1.5px solid #dee2e6;\n    cursor: text;\n}\n/* Комментарий-спан внутри edit area */\n#cem-edit-area .verse-comment { border-radius: 3px; padding: 0 2px; }\n#cem-edit-area .verse-comment::after {\n    content: attr(data-cnum); font-size: 9px; font-weight: 700;\n    vertical-align: super; color: #fff;\n    background: #e67e22; border-radius: 3px;\n    padding: 0 3px; margin-left: 1px; pointer-events: none;\n}\n\n/* ── Comments list ─────────────────────────────────────── */\n.cem-comments {\n    flex-shrink: 0; padding: 10px 14px;\n    background: #fafbfc; max-height: 170px; overflow-y: auto;\n    border-bottom: 1.5px solid #dee2e6;\n}\n.cem-comments-hdr {\n    display: flex; align-items: center; justify-content: space-between;\n    margin-bottom: 8px; font-size: 12px; font-weight: 700;\n    color: #888; text-transform: uppercase; letter-spacing: .6px;\n}\n.cem-add-c-btn {\n    padding: 3px 10px; border: 1.5px solid #1a6db5;\n    background: #e8f1fb; border-radius: 6px; cursor: pointer;\n    font-size: 12px; color: #1a6db5; font-weight: 600; transition: background .12s;\n}\n.cem-add-c-btn:hover { background: #d0e4f7; }\n.cem-no-c { font-size: 13px; color: #b0b8c1; font-style: italic; padding: 4px 2px; }\n\n.cem-c-item {\n    display: flex; align-items: flex-start; gap: 8px;\n    padding: 6px 10px; background: #fff;\n    border: 1.5px solid #e8eaed; border-radius: 8px;\n    margin-bottom: 6px; font-size: 13px;\n}\n.cem-c-num {\n    width: 18px; height: 18px; background: #e67e22; color: #fff;\n    border-radius: 50%; font-size: 10px; font-weight: 700;\n    display: flex; align-items: center; justify-content: center;\n    flex-shrink: 0; margin-top: 1px;\n}\n.cem-c-body { flex: 1; min-width: 0; }\n.cem-c-hl { font-weight: 600; color: #555; font-size: 12px; margin-bottom: 1px;\n    white-space: nowrap; overflow: hidden; text-overflow: ellipsis; }\n.cem-c-txt { color: #2c3e50; line-height: 1.4; }\n.cem-c-del {\n    flex-shrink: 0; background: none; border: none;\n    color: #bbb; font-size: 16px; cursor: pointer; padding: 0 2px;\n    transition: color .12s; line-height: 1;\n}\n.cem-c-del:hover { color: #e53935; }\n\n/* ── Footer ────────────────────────────────────────────── */\n.cem-footer {\n    padding: 10px 18px; background: #f8f9fa;\n    border-top: 1.5px solid #dee2e6;\n    display: flex; justify-content: flex-end; gap: 10px; flex-shrink: 0;\n}\n.cem-cancel-btn {\n    padding: 7px 20px; border: 1.5px solid #dee2e6;\n    background: #fff; border-radius: 8px; cursor: pointer;\n    font-size: 13px; font-weight: 500; color: #666; transition: background .12s;\n}\n.cem-cancel-btn:hover { background: #f0f0f0; }\n.cem-save-btn {\n    padding: 7px 22px; border: none; background: #1a6db5;\n    color: #fff; border-radius: 8px; cursor: pointer;\n    font-size: 13px; font-weight: 600; transition: background .12s;\n    box-shadow: 0 2px 6px rgba(26,109,181,.22);\n}\n.cem-save-btn:hover { background: #155a96; }\n\n/* verse-comment на дисплее (sermon_layout) */\n.verse-comment { border-radius: 3px; padding: 0 2px; }\n`}